import React from 'react';
import { Card, CardContent, Box, Typography, Chip, Stack } from '@mui/material';
import response from './response.json';

interface DriverLocation {
  latitude: number;
  longitude: number;
}

interface WidgetData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    orderStatus: string;
    estimatedDeliveryTime: string;
    driverLocation: DriverLocation;
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: [];
  };
}

export default function Widget() {
  const { data, meta } = response as WidgetData;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 280,
        maxWidth: 380,
        bgcolor: meta.theme === 'light' ? '#FFFFFF' : '#333333',
        borderColor: meta.primaryColor,
        borderWidth: 2,
        borderRadius: 3,
        p: 2,
        mb: 1,
      }}
      elevation={2}
    >
      <CardContent>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: meta.primaryColor }}>
              {data.widget.app} - Delivery Status
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Order Status: <strong>{data.data.orderStatus}</strong>
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Estimated Delivery: <strong>{data.data.estimatedDeliveryTime}</strong>
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            <Chip
              label={`Latitude: ${data.data.driverLocation.latitude.toFixed(4)}`}
              sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: meta.accentColor }}
            />
            <Chip
              label={`Longitude: ${data.data.driverLocation.longitude.toFixed(4)}`}
              sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: meta.accentColor }}
            />
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
